"use client";

import type { Route } from "next";
import { useRouter } from "next/navigation";
import type { ChangeEvent } from "react";
import { useEffect, useState } from "react";

import {
	type BrandProfile,
	loadBrandProfile,
	saveBrandProfile,
} from "@/lib/brand-profile";

import { BrandPreview } from "./brand-preview";

const initialState: BrandProfile = {
	name: "Acme Engineering",
	voice:
		"Technical but with humor. We hate marketing bullshit and write like engineers talk on Twitter — direct, slightly sarcastic, never corporate. We're skeptical of hype and love showing real numbers. When we ship something, we explain it like we're explaining to a friend who codes.",
	tone: {
		formalCasual: 75,
		seriousPlayful: 60,
		directStorytelling: 25,
	},
};

type ToneKey = keyof BrandProfile["tone"];

type SliderRowProps = {
	leftLabel: string;
	rightLabel: string;
	value: number;
	onChange: (value: number) => void;
	id: string;
};

function SliderRow({
	leftLabel,
	rightLabel,
	value,
	onChange,
	id,
}: SliderRowProps) {
	const activeRight = value >= 50;
	return (
		<div className="grid grid-cols-[90px_1fr_90px] items-center gap-4">
			<div
				className={`text-right text-[12px] ${
					activeRight
						? "text-[var(--color-text-muted)]"
						: "text-[var(--color-text)]"
				}`}
			>
				{leftLabel}
			</div>
			<div className="relative h-[6px] rounded-[3px] bg-white/[0.08]">
				<div
					className="absolute top-0 bottom-0 left-0 rounded-[3px]"
					style={{
						width: `${value}%`,
						background: "rgba(229,38,124,0.30)",
					}}
				/>
				<div
					className="-translate-x-1/2 -translate-y-1/2 pointer-events-none absolute top-1/2 h-4 w-4 rounded-full"
					style={{
						left: `${value}%`,
						background: "var(--color-magenta)",
						boxShadow:
							"0 0 0 4px rgba(229,38,124,0.18), 0 2px 6px rgba(0,0,0,0.35)",
					}}
				/>
				<input
					id={id}
					type="range"
					min={0}
					max={100}
					value={value}
					onChange={(e: ChangeEvent<HTMLInputElement>) =>
						onChange(Number(e.target.value))
					}
					aria-label={`${leftLabel} to ${rightLabel}`}
					className="absolute inset-0 h-full w-full cursor-pointer opacity-0"
				/>
			</div>
			<div
				className={`text-left text-[12px] ${
					activeRight
						? "text-[var(--color-text)]"
						: "text-[var(--color-text-muted)]"
				}`}
			>
				{rightLabel}
			</div>
		</div>
	);
}

export function BrandForm() {
	const router = useRouter();
	const [profile, setProfile] = useState<BrandProfile>(initialState);

	useEffect(() => {
		const existing = loadBrandProfile();
		if (existing) {
			setProfile(existing);
		}
	}, []);

	function setName(name: string) {
		setProfile((p) => ({ ...p, name }));
	}

	function setVoice(voice: string) {
		setProfile((p) => ({ ...p, voice }));
	}

	function setTone(key: ToneKey, value: number) {
		setProfile((p) => ({ ...p, tone: { ...p.tone, [key]: value } }));
	}

	function handleSave() {
		saveBrandProfile(profile);
		router.push("/source" as Route);
	}

	function handleSkip() {
		router.push("/source" as Route);
	}

	return (
		<div className="grid grid-cols-[720px_360px] gap-10 px-20 py-20">
			<div>
				<h1 className="m-0 mb-[6px] font-semibold text-[24px] text-[var(--color-text)] tracking-[-0.012em]">
					Define your brand
				</h1>
				<p className="m-0 text-[14px] text-[var(--color-text-muted)]">
					We'll use this every time we generate. You can edit it later.
				</p>

				<div className="mt-10 flex flex-col gap-8">
					<div>
						<label
							htmlFor="brand-name"
							className="mono mb-[10px] block font-medium text-[11px] text-[var(--color-text-muted)] uppercase tracking-[0.08em]"
						>
							Brand name
						</label>
						<input
							id="brand-name"
							className="h-11 w-full rounded-md border border-[var(--color-border)] bg-[var(--color-elev-1)] px-[14px] text-[14px] text-[var(--color-text)] outline-none transition-[border-color,background-color] duration-[120ms] focus:border-[var(--color-border-strong)] focus:bg-[var(--color-elev-2)]"
							value={profile.name}
							onChange={(e) => setName(e.target.value)}
							spellCheck={false}
						/>
						<div className="mt-2 text-[11px] text-[var(--color-text-dim)]">
							This is how we'll refer to your brand internally.
						</div>
					</div>

					<div>
						<label
							htmlFor="brand-voice"
							className="mono mb-[10px] block font-medium text-[11px] text-[var(--color-text-muted)] uppercase tracking-[0.08em]"
						>
							Voice description
						</label>
						<textarea
							id="brand-voice"
							rows={5}
							className="min-h-[140px] w-full resize-y rounded-md border border-[var(--color-border)] bg-[var(--color-elev-1)] px-[14px] py-3 text-[14px] text-[var(--color-text)] leading-[1.55] outline-none transition-[border-color,background-color] duration-[120ms] focus:border-[var(--color-border-strong)] focus:bg-[var(--color-elev-2)]"
							value={profile.voice}
							onChange={(e) => setVoice(e.target.value)}
						/>
						<div className="mt-2 text-[11px] text-[var(--color-text-dim)]">
							The more specific, the better. We'll learn from your tone.
						</div>
					</div>

					<div>
						<div className="mono mb-[10px] block font-medium text-[11px] text-[var(--color-text-muted)] uppercase tracking-[0.08em]">
							Tone
						</div>
						<div className="mt-[-2px] mb-3 text-[12px] text-[var(--color-text-muted)]">
							Three knobs that shape how we write.
						</div>
						<div className="mt-1 flex flex-col gap-6">
							<SliderRow
								id="tone-formal-casual"
								leftLabel="Formal"
								rightLabel="Casual"
								value={profile.tone.formalCasual}
								onChange={(v) => setTone("formalCasual", v)}
							/>
							<SliderRow
								id="tone-serious-playful"
								leftLabel="Serious"
								rightLabel="Playful"
								value={profile.tone.seriousPlayful}
								onChange={(v) => setTone("seriousPlayful", v)}
							/>
							<SliderRow
								id="tone-direct-storytelling"
								leftLabel="Direct"
								rightLabel="Storytelling"
								value={profile.tone.directStorytelling}
								onChange={(v) => setTone("directStorytelling", v)}
							/>
						</div>
					</div>
				</div>

				<div className="mt-10 flex items-center gap-4">
					<button
						type="button"
						onClick={handleSave}
						className="inline-flex h-11 w-[240px] items-center justify-center gap-2 rounded-md border border-[var(--color-magenta)] bg-[var(--color-magenta)] px-4 font-medium text-[14px] text-white transition-[background-color,transform] duration-[120ms] hover:bg-[#ED2F86] active:translate-y-[1px]"
					>
						Save brand profile
					</button>
					<button
						type="button"
						onClick={handleSkip}
						className="inline-flex h-11 items-center justify-center gap-2 rounded-md border border-[var(--color-border)] bg-transparent px-[18px] font-medium text-[14px] text-[var(--color-text)] transition-[background-color,border-color,transform] duration-[120ms] hover:border-[var(--color-border-strong)] hover:bg-[var(--color-elev-1)] active:translate-y-[1px]"
					>
						Skip for now
					</button>
				</div>
			</div>

			<BrandPreview profile={profile} />
		</div>
	);
}

export default BrandForm;

input.content:
"use client";

import type { BrandProfile } from "@/lib/brand-profile";

type Props = {
	profile: BrandProfile;
};

function toneWord(value: number, low: string, mid: string, high: string) {
	if (value <= 33) return low;
	if (value >= 67) return high;
	return mid;
}

function deriveToneWords(tone: BrandProfile["tone"]) {
	return [
		toneWord(tone.formalCasual, "formal", "balanced", "casual"),
		toneWord(
			tone.seriousPlayful,
			"serious",
			"slightly playful",
			"playful",
		),
		toneWord(
			tone.directStorytelling,
			"direct",
			"narrative",
			"storytelling",
		),
	];
}

const DEFAULT_DOS = [
	"show real numbers",
	"write like talking to a friend who codes",
];
const DEFAULT_DONTS = ["use marketing language", "claim breakthroughs"];

export function BrandPreview({ profile }: Props) {
	const toneWords = deriveToneWords(profile.tone);
	const dos = profile.rules?.dos ?? DEFAULT_DOS;
	const donts = profile.rules?.donts ?? DEFAULT_DONTS;
	const traits = (() => {
		if (profile.examples && profile.examples.length > 0) {
			return profile.examples;
		}
		const inferred: string[] = [];
		if (/technical|engineer|code/i.test(profile.voice)) inferred.push("technical");
		if (/skeptic|hype/i.test(profile.voice)) inferred.push("skeptical of hype");
		if (/humor|sarcas|fun/i.test(profile.voice)) inferred.push("engineer humor");
		if (inferred.length === 0) inferred.push(...toneWords);
		return inferred;
	})();

	return (
		<aside className="sticky top-6 self-start">
			<div className="flex flex-col rounded-md border border-[var(--color-border)] bg-[var(--color-elev-1)] p-6">
				<div className="mono text-[11px] text-[var(--color-text-muted)] uppercase tracking-[0.08em]">
					Compiled brand profile
				</div>
				<div className="mono mt-1 inline-flex items-center gap-[6px] text-[11px] text-[var(--color-text-muted)]">
					<span
						className="inline-block h-[6px] w-[6px] rounded-full"
						style={{
							background: "var(--color-green)",
							boxShadow: "0 0 0 3px rgba(45,106,79,0.18)",
						}}
					/>
					<span>Live preview</span>
				</div>

				<div className="mt-5 flex flex-col gap-4">
					<div className="flex flex-col gap-1">
						<div className="mono text-[11px] text-[var(--color-text-muted)] uppercase tracking-[0.06em]">
							name
						</div>
						<div className="text-[13px] text-[var(--color-text)] leading-[1.5]">
							{profile.name || "—"}
						</div>
					</div>

					<div className="flex flex-col gap-1">
						<div className="mono text-[11px] text-[var(--color-text-muted)] uppercase tracking-[0.06em]">
							tone
						</div>
						<div className="text-[13px] text-[var(--color-text)] leading-[1.5]">
							{toneWords.join(", ")}
						</div>
					</div>

					<div className="flex flex-col gap-1">
						<div className="mono text-[11px] text-[var(--color-text-muted)] uppercase tracking-[0.06em]">
							voice_traits
						</div>
						<div className="mt-[2px] flex flex-wrap gap-[6px]">
							{traits.map((trait) => (
								<span
									key={trait}
									className="rounded border border-[var(--color-border)] bg-white/[0.03] px-2 py-[3px] text-[11.5px] text-[var(--color-text)]"
								>
									{trait}
								</span>
							))}
						</div>
					</div>

					<div className="flex flex-col gap-1">
						<div className="mono text-[11px] text-[var(--color-text-muted)] uppercase tracking-[0.06em]">
							writing_rules
						</div>
						<div className="mt-1 flex flex-col gap-[6px]">
							{dos.map((rule) => (
								<div
									key={`do-${rule}`}
									className="grid grid-cols-[36px_1fr] items-baseline text-[13px] text-[var(--color-text)] leading-[1.45]"
								>
									<span
										className="mono font-semibold text-[10.5px] tracking-[0.06em]"
										style={{ color: "#6FBF95" }}
									>
										DO
									</span>
									<span>{rule}</span>
								</div>
							))}
							{donts.map((rule) => (
								<div
									key={`dont-${rule}`}
									className="grid grid-cols-[36px_1fr] items-baseline text-[13px] text-[var(--color-text)] leading-[1.45]"
								>
									<span
										className="mono font-semibold text-[10.5px] tracking-[0.06em]"
										style={{ color: "#C97C7C" }}
									>
										DON'T
									</span>
									<span>{rule}</span>
								</div>
							))}
						</div>
					</div>

					<div className="flex flex-col gap-1">
						<div className="mono text-[11px] text-[var(--color-text-muted)] uppercase tracking-[0.06em]">
							voice_description
						</div>
						<div className="text-[12px] text-[var(--color-text-muted)] leading-[1.5]">
							{profile.voice
								? profile.voice.slice(0, 220) +
								  (profile.voice.length > 220 ? "…" : "")
								: "—"}
						</div>
					</div>
				</div>

				<div
					className="mono mt-5 inline-flex items-center gap-2 border-t pt-[14px] text-[11px] text-[var(--color-text-muted)]"
					style={{ borderColor: "rgba(255,255,255,0.06)" }}
				>
					<span className="brand-pulse inline-block h-[6px] w-[6px] rounded-full bg-[var(--color-magenta)]" />
					<span>Synced</span>
				</div>
			</div>
			<style jsx>{`
				.brand-pulse {
					animation: brand-pulse 1.6s ease-out infinite;
				}
				@keyframes brand-pulse {
					0% { box-shadow: 0 0 0 0 rgba(229,38,124,0.55); }
					70% { box-shadow: 0 0 0 6px rgba(229,38,124,0); }
					100% { box-shadow: 0 0 0 0 rgba(229,38,124,0); }
				}
			`}</style>
		</aside>
	);
}

export default BrandPreview;

